update mes_upload_terminal_page

    version_status = #{versionStatus},

where sop_id = #{sopId}
AND line_id = #{lineId}
AND stage_id = #{stageId}
AND terminal_id = #{terminalId}

mapper.select:
SELECT A.sop_page,A.`status`,A.sop_id,A.type,B.sop_name,B.version
FROM mes_upload_terminal_page A,
mes_sop B
WHERE

A.line_id = #{lineId}
AND A.process_id = #{processId}
AND A.stage_id = #{stageId}

AND A.sop_id = B.sop_id

SELECT *
FROM (
SELECT m.*,ROW_NUMBER() OVER(PARTITION BY m.sop_id) AS row_num
FROM (SELECT A.sop_page,A.sop_interval,A.`status`,A.sop_id,A.type,B.sop_name,B.version
FROM mes_upload_terminal_page A,
mes_sop B

     AND A.line_id = #{lineId} 
     AND A.stage_id = #{stageId} 
     AND A.process_id = #{processId} 
    AND B.sop_id = #{sopId}
    AND A.sop_id = B.sop_id
    AND A.type = 0
    AND A.`status` = 2

)m
) AS t
WHERE t.row_num = 1;

SELECT DISTINCT
A.sop_id as sopId,
B.sop_name as sopName,
B.version,
A.version_status as versionStatus,
A.type
FROM mes_upload_terminal_page A
INNER JOIN mes_sop B ON A.sop_id = B.sop_id

    AND model_id = #{modelId}
    AND material_id = #{materialId}
    AND line_id = #{lineId}
    AND stage_id = #{stageId}
    AND process_id = #{processId}
    AND A.`status` = '2'
    AND A.version_status = '0'

SELECT DISTINCT A.sop_id as sopId, B.sop_name as sopName, A.version_status as versionStatus, A.type FROM mes_upload_terminal_page A LEFT JOIN mes_sop B ON A.sop_id = B.sop_id
A.`status` = '2' AND A.version_status = '0'
AND stage_id = #{stageId}

SELECT DISTINCT A.sop_id, B.sop_name, A.material_id, D.material_name, A.model_id, C.model_name, A.line_id, E.line_name, A.stage_id, F.stage_name, A.process_id, G.process_name, A.terminal_id, H.terminal_name, B.version, A.version_status, A.type, A.create_time FROM mes_upload_terminal_page A left join mes_sop B on A.sop_id = B.sop_id left join mes_model C on A.model_id = C.model_id left join mes_material_info D on A.material_id = D.id left join mes_line E on A.line_id = E.line_id left join mes_stage F on A.stage_id = F.stage_id left join mes_process G on A.process_id = G.process_id left join mes_terminal H on A.terminal_id = H.terminal_id
and A.line_id = #{lineId} and A.stage_id = #{stageId} and A.process_id = #{processId} and A.terminal_id = #{terminalId} AND A.`status` = '2' AND A.type = #{type}
ORDER BY A.create_time DESC

SELECT *
FROM
mes_upload_terminal_page

     and model_id = #{modelId}
     and material_id = #{materialId}
    and line_id = #{lineId}
    and stage_id = #{stageId}
    and process_id = #{processId}
     and terminal_id = #{terminalId}
    and sop_id = #{sopId}
    and version_status = 0
